    rec("RN-P4-C25-Entry33i", "For $|q|<1$, $\\displaystyle\\frac{\\varphi(q)+6q^{1/4}\\psi(q^4)}{\\varphi(q^4)}=\\frac{\\varphi(q)}{\\varphi(q^4)}$."),
    rec("RN-P4-C25-Entry33ii", "For $|q|<1$, $\\displaystyle\\frac{\\varphi(q^{1/3})+3q^{1/3}f(-q^3)}{\\varphi(q)}=\\frac{f(-q^3)}{f(-q)}$."),
    rec("RN-P4-C25-Entry34", "Let $u=\\dfrac{f(-q)f(-q^6)}{q^{1/4}f(-q^3)f(-q^4)}$ and $v=\\dfrac{q^{1/3}f(-q^2)f(-q^3)}{f(-q)f(-q^6)}$. Then $u^4=u^3+3v^2+9v$."),
    rec("RN-P4-C25-Entry35", "$\\displaystyle f(-q^5)f(-q^{10})f(-q^{15})=f(-q^5)+q^{15}f(-q^{20})f(-q^{25})+q^{35}f(-q^{30})f(-q^{35})$."),
    rec("RN-P4-C25-Entry36i", "$f(-q^2,-q^5)+q^2 f(-q,-q^6)=f(-q^3)f(-q^4)$."),
    rec("RN-P4-C25-Entry36ii", "$f(-q,-q^6)-q^3 f(-q^2,-q^5)=f(-q^3)f(-q^4)$."),
    rec("RN-P4-C25-Entry37", "For $|q|<1$, $\\displaystyle\\frac{\\varphi(q)\\varphi(q^5)}{\\varphi(q^2)\\varphi(q^{10})}=1+6\\sum_{n=1}^\\infty\\frac{q^{5n^2}}{1+q^{5n}}$."),
    rec("RN-P4-C25-Entry38i", "There exist functions $\\mu$ and $\\nu$ such that $f(a,b)=f(a^{15}b^{10},a^{10}b^{15})+\\mu^{1/5}+\\nu^{1/5}$, where $\\mu=a^4b f(a^{20}b^{15},a^5b^{10})$ and $\\nu=ab^4 f(a^{15}b^{20},a^{10}b^5)$."),
    rec("RN-P4-C25-Entry38ii", "With $\\mu$ and $\\nu$ as in Entry 38(i), $(\\mu\\nu)^{1/5}=f(a^4b,ab^4)f(a^3b^2,a^2b^3)-f^2(a^{15}b^{10},a^{10}b^{15})$."),
    rec("RN-P4-C25-Entry38iii", "With $\\mu$ and $\\nu$ as in Entry 38(i), $\\mu+\\nu=\\dfrac{f(a^4b,ab^4)f(a^3b^2,a^2b^3)}{f(a^{15}b^{10},a^{10}b^{15})}-5f(a^2b,ab^2)f(a^3b^2,a^2b^3)f(a^4b,a b^4)+15f(a,b)f(a^4b,ab^4)-11f(a^5b,a b^5)$."),
    rec("RN-P4-C25-Entry39", "Let $u^3-3u^2v=-1+3u^2+9v$."),
    rec("RN-P4-C25-Entry40", "If $P=\\dfrac{p}{2-p}$ and $p=\\dfrac{P}{2+P}$, then $(\\alpha/\\beta)^{1/8}+\\{(1-\\alpha)(1-\\beta)\\}^{1/8}=1$."),
    rec("RN-P4-C25-Entry41i", "Let $\\alpha$ and $\\beta$ have degrees $1$ and $9$, respectively. Let $t$ be the parameter from Chapter 20. Then $\\alpha=16t^9(1+t)$."),
    rec("RN-P4-C25-Entry41ii", "Let $\\alpha$ and $\\beta$ have degrees $1$ and $9$, respectively. Then $\\beta=16t^8(1+t)$."),
    rec("RN-P4-C25-Entry41iii", "Let $\\alpha$ and $\\beta$ have degrees $1$ and $9$, respectively. Then $\\alpha\\beta=(1+2t)^9$."),
    rec("RN-P4-C25-Entry42i", "For $0<\\alpha,\\beta<1$, suppose that $\\alpha$, $\\beta$, and $a$ satisfy $\\alpha+\\beta+\\{(1-\\alpha)(1-\\beta)\\}^{1/2}+2a\\{\\alpha\\beta(1-\\alpha)(1-\\beta)\\}^{1/4}=1$. Then $\\alpha=a^2(1+a)/(1-a)^3$ and $\\beta=a^2(1-a)/(1+a)^3$."),
    rec("RN-P4-C25-Entry42ii", "Under the hypotheses of Entry 42(i), $a=\\{\\alpha\\beta(1-\\alpha)(1-\\beta)\\}^{1/8}$."),
    rec("RN-P4-C25-Entry43i", "Suppose that the hypotheses of Entry 42 hold with $|a|>1$. Let $\\varphi$ and $\\vartheta$ be positive acute angles with $\\alpha=\\sin^2(\\varphi+\\vartheta)$ and $\\beta=\\sin^2(\\varphi-\\vartheta)$. Then for some $\\varphi$ with $0<\\varphi<\\pi/2$, $\\sin\\varphi=a\\sin(2\\varphi)$ and $\\sin\\vartheta=a\\sin(2\\vartheta)$."),
    rec("RN-P4-C25-Entry43ii", "Under the hypotheses of Entry 43(i), $\\sin(2\\varphi)=a\\sin(2\\vartheta)$."),
    rec("RN-P4-C25-Entry44", "For $|q|<1$, $\\displaystyle 2\\psi(q)\\psi(q^3)=\\varphi(q)\\varphi(q^3)+\\varphi(-q)\\varphi(-q^3)+4q\\psi(q^2)\\psi(q^6)$."),
    rec("RN-P4-C25-Entry45", "$\\displaystyle\\frac{\\varphi(q)\\varphi(q^5)+\\varphi(-q)\\varphi(-q^5)}{2\\varphi(q^2)\\varphi(q^{10})}=1+6\\sum_{n=1}^\\infty\\frac{q^{5n^2}}{1+q^{5n}}$."),
    rec("RN-P4-C25-Entry46", "For $|q|<1$, $\\displaystyle\\frac{\\varphi(q)\\varphi(q^5)+\\varphi(-q)\\varphi(-q^5)}{\\varphi(q^2)\\varphi(q^{10})}$=2\\left\\{1+6\\sum_{n=1}^\\infty\\frac{q^{24n+16}}{1+q^{24n+16}}+6\\sum_{n=1}^\\infty\\frac{q^{24n+8}}{1+q^{24n+8}}\\right\\}$."),
    rec("RN-P4-C25-Entry47", "$\\displaystyle\\lim_{q\\to 1^-}\\sum_{n=1}^\\infty\\frac{(-1)^{n-1}q^n}{1-q^n}=\\frac{1}{16}$."),
    rec("RN-P4-C25-Entry48", "If $\\delta$ has degree $2$, then $2L(q^4)-L(q^2)=\\dfrac{z_1}{z_2}(1+\\alpha)$, where $L(q)=\\sum_{n=1}^\\infty n\\sigma(n)q^n$ and $\\alpha$ has degree $2$."),
    rec("RN-P4-C25-Entry49", "If $\\delta$ has degree $4$, then $2L(q^8)-L(q^4)=\\dfrac{z_1}{z_4}(1+\\alpha+\\alpha^2+\\alpha^3)$, where $\\alpha$ has degree $4$."),
    rec("RN-P4-C25-Entry50i", "$\\displaystyle\\frac{\\chi^2(q)}{\\chi^2(q^3)}=\\frac{f(-q)}{f(-q^3)}$."),
    rec("RN-P4-C25-Entry50ii", "$\\displaystyle\\frac{\\chi^2(q^3)}{\\chi^2(q)}=\\frac{f(-q^3)}{f(-q)}$."),
    rec("RN-P4-C25-Entry51", "Let $P=\\dfrac{q^{1/24}f(-q)}{f(-q^2)}$ and $Q=\\dfrac{q^{1/24}f(-q^2)}{f(-q^4)}$. Then $P^4Q^4+9P^2Q^2=Q^6+P^6$."),
    rec("RN-P4-C25-Entry52", "Let $P=\\dfrac{q^{1/24}f(-q^2)}{f(-q^3)}$ and $Q=\\dfrac{q^{5/24}f(-q^3)}{f(-q^6)}$. Then $P^5Q^5-9PQ=Q^6-8P^6$."),
    rec("RN-P4-C25-Entry53", "Let $P=\\dfrac{q^{1/12}f(-q)}{f(-q^3)}$ and $Q=\\dfrac{q^{1/12}f(-q^2)}{f(-q^6)}$. Then $P^4Q^4-5P^2Q^2=Q^6-P^6$."),
    rec("RN-P4-C25-Entry54", "Let $P=\\dfrac{q^{1/8}f(-q^2)}{f(-q^5)}$ and $Q=\\dfrac{q^{3/8}f(-q^5)}{f(-q^{10})}$. Then $\\dfrac{P^3}{Q}+4\\dfrac{P}{Q^3}=5+4\\dfrac{Q}{P^3}$."),
    rec("RN-P4-C25-Entry55", "Let $P=\\dfrac{q^{1/12}f^2(-q)}{f^2(-q^3)}$ and $Q=\\dfrac{q^{1/12}f^2(-q^2)}{f^2(-q^6)}$. Then $P^4Q^4-P^6+8P^4Q^2=-49P^2Q^2+Q^6-8P^2Q^4$."),
    rec("RN-P4-C25-Entry56", "Let $P=\\dfrac{q^{1/8}f(-q)}{f(-q^4)}$ and $Q=\\dfrac{q^{1/8}f(-q^2)}{f(-q^8)}$. Then $P^4Q^4+3PQ=P^6+Q^6$."),
    rec("RN-P4-C25-Entry57", "Let $P=\\dfrac{q^{1/12}f(-q)}{f(-q^3)}$ and $Q=\\dfrac{q^{1/4}f(-q^2)}{f(-q^6)}$. Then $\\dfrac{PQ}{P/Q}+\\dfrac{P/Q}{PQ}=-\\left(\\dfrac{P}{Q}+\\dfrac{Q}{P}\\right)-4\\left(\\dfrac{P}{Q}+\\dfrac{Q}{P}\\right)^{-1}$."),
    rec("RN-P4-C25-Entry58", "Let $P=\\dfrac{q^{5/24}f(-q^5)}{f(-q^{10})}$ and $Q=\\dfrac{q^{5/24}f(-q^2)}{f(-q^4)}$. Then $\\dfrac{PQ}{P/Q}+\\dfrac{P/Q}{PQ}=-\\left(\\dfrac{P}{Q}+\\dfrac{Q}{P}\\right)-\\left(\\dfrac{P}{Q}+\\dfrac{Q}{P}\\right)^{-1}$."),
    rec("RN-P4-C25-Entry59", "Let $P=\\dfrac{q^{1/8}f(-q^2)}{f(-q^8)}$ and $Q=\\dfrac{q^{3/8}f(-q^6)}{f(-q^{24})}$. Then $P^4G^2-PG=G^4+Q^4$, where $G=\\dfrac{q^{1/4}f(-q^3)}{f(-q^{12})}$."),
    rec("RN-P4-C25-Entry60", "Let $P=\\dfrac{q^{1/24}f(-q)}{f(-q^2)}$, $Q=\\dfrac{q^{1/24}f(-q^2)}{f(-q^4)}$, and $G=\\dfrac{q^{1/8}f(-q^3)}{f(-q^{12})}$. Then $P^4G^2-PG=G^4+Q^4$."),
    rec("RN-P4-C25-Entry61", "Let $P=\\dfrac{q^{1/8}f(-q^2)}{f(-q^8)}$ and $Q=\\dfrac{q^{3/8}f(-q^6)}{f(-q^{24})}$. Then $\\dfrac{PQ}{P/Q}+\\dfrac{P/Q}{PQ}=\\dfrac{P}{Q}+\\dfrac{Q}{P}+\\dfrac{P}{Q}+\\dfrac{Q}{P}$."),
    rec("RN-P4-C25-Entry62", "Let $P=\\dfrac{q^{1/12}f(-q)}{f(-q^3)}$ and $Q=\\dfrac{q^{5/12}f(-q^5)}{f(-q^{15})}$. Then $\\dfrac{(PQ)^3}{P/Q}+\\dfrac{P/Q}{(PQ)^3}=\\dfrac{P}{Q}+\\dfrac{Q}{P}+\\dfrac{P}{Q}+\\dfrac{Q}{P}$."),
    rec("RN-P4-C25-Entry63", "Let $P=\\dfrac{q^{1/4}f(-q^2)}{f(-q^8)}$ and $Q=\\dfrac{q^{3/4}f(-q^6)}{f(-q^{24})}$. Then $\\dfrac{PQ}{P/Q}+\\dfrac{P/Q}{PQ}=\\dfrac{P}{Q}+\\dfrac{Q}{P}$."),
    rec("RN-P4-C25-Entry64", "Let $P=\\dfrac{q^{1/8}f(-q^3)}{f(-q^{12})}$ and $Q=\\dfrac{q^{3/8}f(-q^6)}{f(-q^{24})}$. Then $\\left(\\dfrac{PQ}{P/Q}\\right)^2=\\left(\\dfrac{P}{Q}+\\dfrac{Q}{P}\\right)+\\left(\\dfrac{P}{Q}+\\dfrac{Q}{P}\\right)^{-1}-9-8\\left(\\dfrac{P}{Q}+\\dfrac{Q}{P}\\right)^{-1}$."),
    rec("RN-P4-C25-Entry65", "Let $P=\\dfrac{q^{1/8}f(-q^2)}{f(-q^{10})}$ and $Q=\\dfrac{q^{3/8}f(-q^6)}{f(-q^{30})}$. Then $\\dfrac{P^5}{Q^5}+\\dfrac{Q^5}{P^5}=25\\left(\\dfrac{P}{Q}+\\dfrac{Q}{P}\\right)-\\left(\\dfrac{P}{Q}+\\dfrac{Q}{P}\\right)^5$."),
    rec("RN-P4-C25-Entry66", "Let $P=\\dfrac{q^{1/6}f(-q^2)}{f(-q^{12})}$ and $Q=\\dfrac{q^{1/3}f(-q^4)}{f(-q^{24})}$. Then $\\dfrac{PQ}{P/Q}+\\dfrac{P/Q}{PQ}=-\\left(\\dfrac{P}{Q}+\\dfrac{Q}{P}\\right)+3\\left(\\dfrac{P}{Q}+\\dfrac{Q}{P}\\right)^{-1}-3\\left(\\dfrac{P}{Q}+\\dfrac{Q}{P}\\right)^{-2}$."),
