    rec("RN-P4-C25-Entry70", "Let $P=\\dfrac{q^{1/6}f(-q^2)}{f(-q^{12})}$ and $Q=\\dfrac{q^{1/3}f(-q^4)}{f(-q^{24})}$. Then $\\dfrac{P^3}{Q^3}+\\dfrac{Q^3}{P^3}=\\left(\\dfrac{P}{Q}+\\dfrac{Q}{P}\\right)^3+\\left(\\dfrac{P}{Q}+\\dfrac{Q}{P}\\right)^{-3}$."),
